#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
int n,Q,dy[N],f[N][30],c[N],dep[N];
vector<int> g[N];
int k_father(int u,int k){
    for(int i=0;i<=int(log2(k));i++)
        if((1<<i)&k)u=f[u][i];
    return u;
}
void DFS(int u){
    for(int i=1;i<=20;i++){
        if(f[u][i-1])f[u][i]=f[f[u][i-1]][i-1];
        else f[u][i]=1;
    }
    for(int i=0;i<g[u].size();i++){
        int v=g[u][i];
        if(v!=f[u][0]){
            f[v][0]=u;
            dep[v]=dep[u]+1;
            c[v]=c[u]+dy[v];
            DFS(v);
        }
    }
    return ;
}
int LCA(int u,int v){
    if(dep[u]!=dep[v]){
        if(dep[u]<dep[v])swap(u,v);
        u=k_father(u,dep[u]-dep[v]);
    }
    if(u==v)return u;
    for(int i=20;i>=0;i--)
        if(f[u][i]!=f[v][i])u=f[u][i],v=f[v][i];
    u=f[u][0],v=f[v][0];
    return u;
}
int main(){
    cin>>n>>Q;
    for(int i=1;i<n;i++){
        int x,y;
        cin>>x>>y;
        g[x].push_back(y);
        g[y].push_back(x);
    }
    for(int i=1;i<=n;i++)dy[i]=g[i].size(),c[i]=dy[i];
    f[1][0]=1;
    DFS(1);
    while(Q--){
        int x,y;
        cin>>x>>y;
        if(x==y){cout<<dy[x]<<endl;continue;}
        int p=LCA(x,y);
        cout<<c[x]+c[y]-2*c[p]+dy[p]<<endl;
    }
    return 0;
}
